import os
import requests
import re

def get_pdb_sequence(pdb_id):
    url = f"https://data.rcsb.org/rest/v1/core/entry/{pdb_id}"
    try:
        response = requests.get(url)
        if response.status_code == 200:
            data = response.json()
            # This is a simplified fetch, real RCSB API requires entity level for sequence
            # But we can try the fasta endpoint
            fasta_url = f"https://www.rcsb.org/fasta/entry/{pdb_id}"
            fasta_res = requests.get(fasta_url)
            if fasta_res.status_code == 200:
                lines = fasta_res.text.splitlines()
                seq = "".join(l.strip() for l in lines if not l.startswith(">"))
                return seq
    except:
        pass
    return None

